async function main() {
  let success = 0, fail = 0;
  for (const item of updates) {
    try {
      const result = await prisma.product.update({
        where: { id: item.id },
        data: { description: item.description }
      });
      const wc = item.description.split(/\s+/).filter(w => w.length > 0).length;
      console.log(`✅ Updated: ${result.slug} [${wc}w]`);
      success++;
    } catch (error) {
      console.error(`❌ Error updating ${item.id}: ${error.message}`);
      fail++;
    }
  }
  console.log(`\n✅ Part 1 complete — ${success} updated, ${fail} failed`);
}
main().then(() => prisma.$disconnect());
